static void
_list_reverse_slice(PyObject **arr, Py_ssize_t lo, Py_ssize_t hi)
{
    /* reverse arr[lo..hi) in-place */
    PyObject **lo_ptr = arr + lo;
    PyObject **hi_ptr = arr + hi;
    --hi_ptr;
    while (lo_ptr < hi_ptr) {
        PyObject *t = *lo_ptr;
        FT_ATOMIC_STORE_PTR_RELEASE(*lo_ptr, *hi_ptr);
        FT_ATOMIC_STORE_PTR_RELEASE(*hi_ptr, t);
        ++lo_ptr;
        --hi_ptr;
    }
}
```

### list_rotate_impl full stub
```c
/*[clinic input]
@critical_section
list.rotate

    n: Py_ssize_t = 1
    /

Rotate list elements left by n positions (negative n rotates right).
[clinic start generated code]*/
static PyObject *
list_rotate_impl(PyListObject *self, Py_ssize_t n)
/*[clinic end generated code: ...]*/
{
    Py_ssize_t len = Py_SIZE(self);
    if (len <= 1)
        Py_RETURN_NONE;
    n %= len;
    if (n < 0)
        n += len;
    /* Three-reversal algorithm: rotate left by n */
    _list_reverse_slice(self->ob_item, 0, n);
    _list_reverse_slice(self->ob_item, n, len);
    _list_reverse_slice(self->ob_item, 0, len);
    Py_RETURN_NONE;
}
```
NOTE: "left rotation by n" means element at index 0 moves to index len-n. Matches `collections.deque.rotate(-n)` semantics (deque.rotate(n) is right rotation). Verify semantics against spec before finalizing.

