### bytes_find_all_impl full stub
```c
/*[clinic input]
@permit_long_summary
@text_signature "($self, sub[, start[, end]], /)"
bytes.find_all

    sub: object
    start: slice_index(accept={int, NoneType}, c_default='0') = None
    end: slice_index(accept={int, NoneType}, c_default='PY_SSIZE_T_MAX') = None
    /

Return a list of all non-overlapping indices where sub is found in B[start:end].
[clinic start generated code]*/
static PyObject *
bytes_find_all_impl(PyBytesObject *self, PyObject *sub, Py_ssize_t start,
                    Py_ssize_t end)
/*[clinic end generated code]*/
{
    char byte;
    Py_buffer subbuf;
    const char *haystack;
    const char *needle;
    Py_ssize_t haystack_len, needle_len, pos, found;
    PyObject *result_list = NULL, *index_obj = NULL;
    PyObject *sub_copy = sub;

    if (!parse_args_finds_byte("find_all", &sub_copy, &byte))
        return NULL;

    haystack = PyBytes_AS_STRING(self);
    haystack_len = PyBytes_GET_SIZE(self);

    if (sub_copy) {
        if (PyObject_GetBuffer(sub_copy, &subbuf, PyBUF_SIMPLE) != 0)
            return NULL;
        needle = subbuf.buf;
        needle_len = subbuf.len;
    } else {
        needle = &byte;
        needle_len = 1;
    }

    ADJUST_INDICES(start, end, haystack_len);

    result_list = PyList_New(0);
    if (result_list == NULL)
        goto error;

    if (needle_len == 0)
        goto done;   /* return empty list for empty needle */

    pos = start;
    while (pos <= end - needle_len) {
        found = stringlib_find(haystack, haystack_len, needle, needle_len, pos);
        if (found == -1)
            break;
        index_obj = PyLong_FromSsize_t(found);
        if (index_obj == NULL)
            goto error;
        if (PyList_Append(result_list, index_obj) < 0) {
            Py_DECREF(index_obj);
            goto error;
        }
        Py_DECREF(index_obj);
        pos = found + needle_len;
    }

done:
    if (sub_copy)
        PyBuffer_Release(&subbuf);
    return result_list;

error:
    Py_XDECREF(result_list);
    if (sub_copy)
        PyBuffer_Release(&subbuf);
    return NULL;
}
```

